const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.openaq&cred_key=eq.openaq_api_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'OpenAQ API Key not configured. Use add_credential to set it up.' } }];
}
const apiKey = creds[0].cred_value;
const API = 'https://api.openaq.org/v3';
const authHeaders = { 'X-API-Key': apiKey };
const NOMINATIM = 'https://nominatim.openstreetmap.org';
const UA = { 'User-Agent': 'n8n-claw-openaq/1.0' };

async function geocode(city) {
  const data = await helpers.httpRequest({
    method: 'GET',
    url: NOMINATIM + '/search?q=' + encodeURIComponent(city) + '&format=json&limit=1',
    headers: UA
  });
  if (!data || data.length === 0) return null;
  return {
    lat: parseFloat(data[0].lat),
    lon: parseFloat(data[0].lon),
    name: data[0].display_name
  };
}

function formatTimestamp(dt) {
  if (!dt) return '';
  if (typeof dt === 'string') return dt;
  if (dt.local) return dt.local;
  if (dt.utc) return dt.utc;
  return '';
}

function healthHint(param, value) {
  if (value == null) return '';
  if (param === 'pm25') {
    if (value <= 15) return 'good';
    if (value <= 25) return 'moderate';
    if (value <= 50) return 'poor';
    return 'unhealthy';
  }
  if (param === 'pm10') {
    if (value <= 25) return 'good';
    if (value <= 50) return 'moderate';
    if (value <= 90) return 'poor';
    return 'unhealthy';
  }
  if (param === 'no2') {
    if (value <= 40) return 'good';
    if (value <= 100) return 'moderate';
    return 'poor';
  }
  if (param === 'o3') {
    if (value <= 100) return 'good';
    if (value <= 180) return 'moderate';
    return 'poor';
  }
  return '';
}

async function resolveCoords(input) {
  if (input.lat && input.lon) {
    return { lat: parseFloat(input.lat), lon: parseFloat(input.lon), name: input.lat + ',' + input.lon };
  }
  if (input.city) {
    const g = await geocode(input.city);
    if (!g) return null;
    return g;
  }
  return null;
}

// === get_air_quality ===
if (action === 'get_air_quality') {
  if (!input.city && !(input.lat && input.lon)) {
    return [{ json: { error: 'Provide either "city" (e.g. Berlin, Essen) or both "lat" and "lon".' } }];
  }
  const radius = Math.min(parseInt(input.radius) || 25000, 25000);
  const coords = await resolveCoords(input);
  if (!coords) return [{ json: { error: 'Could not resolve location: ' + (input.city || input.lat + ',' + input.lon) } }];

  try {
    const locData = await helpers.httpRequest({
      method: 'GET',
      url: API + '/locations?coordinates=' + coords.lat + ',' + coords.lon + '&radius=' + radius + '&limit=1',
      headers: authHeaders
    });
    const loc = locData.results && locData.results[0];
    if (!loc) {
      return [{ json: { result: 'No monitoring station found within ' + (radius / 1000) + 'km of ' + coords.name + '.' } }];
    }

    const sensorMap = {};
    for (const s of (loc.sensors || [])) {
      sensorMap[s.id] = s.parameter;
    }

    const latest = await helpers.httpRequest({
      method: 'GET',
      url: API + '/locations/' + loc.id + '/latest',
      headers: authHeaders
    });

    let result = 'Air quality near ' + coords.name + '\n';
    result += 'Station: ' + loc.name + (loc.locality ? ' (' + loc.locality + ')' : '') + ' — Location ID ' + loc.id + '\n';
    if (loc.provider && loc.provider.name) result += 'Provider: ' + loc.provider.name + '\n';
    result += '\nCurrent measurements:\n';

    const entries = (latest.results || []).map(r => {
      const p = sensorMap[r.sensorsId];
      return { param: p ? p.name : ('sensor-' + r.sensorsId), displayName: p ? p.displayName : null, units: p ? p.units : '', value: r.value, ts: formatTimestamp(r.datetime) };
    });

    const order = ['pm25', 'pm10', 'no2', 'o3', 'so2', 'co', 'no'];
    entries.sort((a, b) => {
      const ai = order.indexOf(a.param);
      const bi = order.indexOf(b.param);
      return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
    });

    if (entries.length === 0) {
      result += '(no recent measurements reported)\n';
    } else {
      for (const e of entries) {
        const label = e.displayName || e.param.toUpperCase();
        const hint = healthHint(e.param, e.value);
        result += '• ' + label + ': ' + e.value + ' ' + e.units + (hint ? ' (' + hint + ')' : '') + ' — ' + e.ts + '\n';
      }
    }
    if (result.length > 5000) result = result.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'OpenAQ request failed: ' + err.message } }];
  }

// === find_stations ===
} else if (action === 'find_stations') {
  if (!input.city && !(input.lat && input.lon)) {
    return [{ json: { error: 'Provide either "city" or both "lat" and "lon".' } }];
  }
  const radius = Math.min(parseInt(input.radius) || 25000, 25000);
  const limit = Math.min(parseInt(input.limit) || 5, 20);
  const coords = await resolveCoords(input);
  if (!coords) return [{ json: { error: 'Could not resolve location: ' + (input.city || input.lat + ',' + input.lon) } }];

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: API + '/locations?coordinates=' + coords.lat + ',' + coords.lon + '&radius=' + radius + '&limit=' + limit,
      headers: authHeaders
    });
    const results = data.results || [];
    if (results.length === 0) {
      return [{ json: { result: 'No stations found within ' + (radius / 1000) + 'km of ' + coords.name + '.' } }];
    }
    let out = 'Found ' + (data.meta && data.meta.found ? data.meta.found : results.length) + ' stations near ' + coords.name + ' (showing ' + results.length + '):\n\n';
    for (const loc of results) {
      out += '**' + loc.name + '** — ID ' + loc.id + '\n';
      if (loc.locality) out += '  Locality: ' + loc.locality + '\n';
      if (loc.country && loc.country.name) out += '  Country: ' + loc.country.name + '\n';
      if (loc.provider && loc.provider.name) out += '  Provider: ' + loc.provider.name + '\n';
      const params = (loc.sensors || []).map(s => s.parameter && s.parameter.name).filter(Boolean);
      if (params.length > 0) out += '  Parameters: ' + params.join(', ') + '\n';
      out += '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'OpenAQ request failed: ' + err.message } }];
  }

// === get_station_history ===
} else if (action === 'get_station_history') {
  const locationId = input.location_id;
  const param = (input.parameter || 'pm25').toLowerCase();
  const days = Math.min(parseInt(input.days) || 7, 7);
  if (!locationId) {
    return [{ json: { error: 'Parameter "location_id" is required (use find_stations to get IDs).' } }];
  }

  try {
    const locData = await helpers.httpRequest({
      method: 'GET',
      url: API + '/locations/' + encodeURIComponent(locationId),
      headers: authHeaders
    });
    const loc = locData.results && locData.results[0];
    if (!loc) return [{ json: { error: 'Station not found: ' + locationId } }];

    const sensor = (loc.sensors || []).find(s => s.parameter && s.parameter.name === param);
    if (!sensor) {
      const available = (loc.sensors || []).map(s => s.parameter && s.parameter.name).filter(Boolean);
      return [{ json: { error: 'Parameter "' + param + '" not available at station ' + loc.name + '. Available: ' + available.join(', ') + '.' } }];
    }

    const now = new Date();
    const from = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
    const dateFrom = from.toISOString().substring(0, 10);
    const dateTo = now.toISOString().substring(0, 10);

    const hist = await helpers.httpRequest({
      method: 'GET',
      url: API + '/sensors/' + sensor.id + '/days?date_from=' + dateFrom + '&date_to=' + dateTo + '&limit=' + days,
      headers: authHeaders
    });
    const rows = hist.results || [];
    if (rows.length === 0) {
      return [{ json: { result: 'No daily data for ' + param + ' at ' + loc.name + ' between ' + dateFrom + ' and ' + dateTo + '.' } }];
    }

    let out = param.toUpperCase() + ' daily values at ' + loc.name + ' (last ' + rows.length + ' days):\n\n';
    for (const r of rows) {
      const date = r.period && r.period.datetimeFrom ? (r.period.datetimeFrom.local || r.period.datetimeFrom.utc || '').substring(0, 10) : '';
      const units = r.parameter && r.parameter.units ? r.parameter.units : '';
      const summary = r.summary || {};
      out += date + ': avg ' + r.value + ' ' + units;
      if (summary.min != null && summary.median != null) {
        out += ' (min ' + summary.min.toFixed(1) + ', median ' + summary.median.toFixed(1) + ', q75 ' + (summary.q75 != null ? summary.q75.toFixed(1) : '-') + ')';
      }
      out += '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'OpenAQ history request failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: get_air_quality, find_stations, get_station_history.' } }];
}
